import React from 'react';
import { useTranslation } from 'react-i18next';

const SocialPreview = () => {
  const { t } = useTranslation();

  return (
    <section style={{ padding: '3rem 0', textAlign: 'center' }}>
      <h2 style={{ color: '#D4A437', marginBottom: '2rem', fontSize: '1.8rem' }}>
        {t('social.followUs', 'Follow Us On Social Media')}
      </h2>
      <div style={{ display: 'flex', justifyContent: 'center', gap: '2rem', flexWrap: 'wrap' }}>
        <div style={{ width: 'fit-content', margin: '0 auto' }}>
          <iframe
            title="Facebook"
            src="https://www.facebook.com/plugins/page.php?href=https%3A%2F%2Fwww.facebook.com%2FImpastoEG%2F&tabs=timeline&width=340&height=500"
            width="340"
            height="500"
            style={{ border: 'none', overflow: 'hidden', borderRadius: '8px', background: '#1a1a1a' }}
            scrolling="no"
            frameBorder="0"
            allowFullScreen={true}
            allow="autoplay; clipboard-write; encrypted-media; picture-in-picture; web-share"
          ></iframe>
        </div>
        <div style={{ width: 'fit-content', margin: '0 auto' }}>
          <iframe
            title="Instagram"
            src="https://widget.simplygram.com/instagram-feed/166002121/recent"
            width="340"
            height="500"
            frameBorder="0"
            scrolling="no"
            allowFullScreen={true}
            style={{ border: 'none', borderRadius: '8px' }}
          ></iframe>
        </div>
      </div>
    </section>
  );
};

export default SocialPreview;
